Advanced Example: Custom Authentication
Here’s how to build a complete authentication system with custom logic:

from fasthtml.common import *
from launch_kit.auth import hash_password, verify_password
from launch_kit.routes.auth import login_route, signup_route, logout_route
from datetime import datetime

# Your database setup (example with dict for simplicity)
users_db = {}

def authenticate_user(email, password):
    """Custom authentication logic"""
    user = users_db.get(email)
    if user and verify_password(password, user['password_hash']):
        return {'email': email, 'name': user['name']}
    return None

def create_user(form_data):
    """Custom user creation logic"""
    email = form_data.get('email')

    # Validation
    if form_data['password'] != form_data['password_confirm']:
        return "Passwords don't match"

    if email in users_db:
        return "Email already registered"

    # Create user
    users_db[email] = {
        'name': form_data['name'],
        'password_hash': hash_password(form_data['password']),
        'created_at': datetime.now()
    }

    return {'email': email, 'name': form_data['name']}

# Create app with session middleware
app, rt = fast_app(
    secret_key='your-secret-key',  # Required for sessions
    pico=True  # Optional: Use Pico CSS for styling
)

# Add auth routes with custom logic
login_route(app, authenticate=authenticate_user)
signup_route(app, create_user=create_user)
logout_route(app)

# Protected route example
@rt("/dashboard")
def get(sess):
    user = sess.get('auth')
    if not user:
        return RedirectResponse('/auth/login', status_code=303)

    return Title("Dashboard"), Main(
        H1(f"Welcome to your dashboard, {user['name']}!"),
        P(f"Logged in as: {user['email']}"),
        Button("Logout", hx_get="/auth/logout", hx_push_url="true")
    )

# Public route
@rt("/")
def get():
    return Title("Launch Kit Demo"), Main(
        H1("Welcome to Launch Kit"),
        P("A FastHTML toolkit for building SaaS applications"),
        Div(
            A("Login", href="/auth/login", cls="button"),
            " ",
            A("Sign Up", href="/auth/signup", cls="button outline"),
            cls="grid"
        )
    )

serve()

Complete Database Example
Here’s how to use the User model and database functions together:

from launch_kit.auth import *
from fasthtml.common import *

# Initialize database
db = init_auth_tables('app.db')

# Create FastHTML app with auth
beforeware = Beforeware(
    user_auth_before,
    skip=['/login', '/signup', '/']
)
app, rt = fast_app(before=beforeware)

@rt('/')
def get():
    return Div(
        H1('Welcome to Launch Kit Auth Demo'),
        A('Sign Up', href='/signup'),
        ' | ',
        A('Login', href='/login')
    )

@rt('/signup')
def get():
    return Div(
        H2('Sign Up'),
        Form(
            Input(name='username', placeholder='Username', required=True),
            Input(name='email', type='email', placeholder='Email', required=True),
            Input(name='password', type='password', placeholder='Password', required=True),
            Button('Sign Up', type='submit'),
            method='post'
        )
    )

@rt('/signup')
def post(username: str, email: str, password: str):
    # Validate input
    errors = validate_user_data(username, email, password)
    if errors:
        return Div(
            *[P(error, style='color: red') for error in errors],
            get()
        )

    # Check availability
    if not is_username_available(db, username):
        return Div(P('Username already taken', style='color: red'), get())
    if not is_email_available(db, email):
        return Div(P('Email already registered', style='color: red'), get())

    # Create user
    user = create_user(db, username, email, password)
    if user:
        return Redirect('/login')

    return Div(P('Registration failed', style='color: red'), get())

@rt('/login')
def get():
    return Div(
        H2('Login'),
        Form(
            Input(name='username_or_email', placeholder='Username or Email', required=True),
            Input(name='password', type='password', placeholder='Password', required=True),
            Button('Login', type='submit'),
            method='post'
        )
    )

@rt('/login')
def post(username_or_email: str, password: str, sess, req):
    # Authenticate user
    user = authenticate_user(db, username_or_email, password)

    if user:
        # Set session
        sess['auth'] = True
        sess['user'] = {'id': user['id'], 'username': user['username'], 'email': user['email']}

        # Track login (now returns a dictionary with login details)
        ip = req.headers.get('x-forwarded-for', req.client.host)
        user_agent = req.headers.get('user-agent')
        login_record = track_login(db, user['id'], ip, user_agent)

        # You can use the login_record if needed, e.g. for analytics
        # login_record contains: id, user_id, ip_address, user_agent, login_time

        return Redirect('/dashboard')

    return Div(P('Invalid credentials', style='color: red'), get())

@rt('/dashboard')
def get(auth, sess):
    user_data = get_user_from_session(sess)
    if not user_data:
        return Redirect('/login')

    return Div(
        H2(f"Welcome, {user_data['username']}!"),
        P(f"Email: {user_data['email']}"),
        A('Logout', href='/logout')
    )

@rt('/logout')
def get(sess):
    sess.clear()
    return Redirect('/')
